import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { format } from 'date-fns';
import { es } from 'date-fns/locale';

// --- CONFIGURACIÓN DE COLORES CORPORATIVOS (Gris Formulario) ---
const COLOR_BORDE: [number, number, number] = [150, 150, 150]; // Gris medio para bordes
const COLOR_FONDO_CABECERA: [number, number, number] = [230, 230, 230]; // Gris claro para fondos
const COLOR_TEXTO: [number, number, number] = [30, 30, 30]; // Casi negro para texto

// === INSTRUCCIONES PARA EL LOGO ===
// Necesitas convertir tu imagen 'logo.png' a una cadena Base64.
// Puedes usar un conversor online (busca "image to base64").
// Pega la cadena larga resultante entre las comillas simples de abajo.
const LOGO_BASE64 = 'data:image/png;base64,';

export const generateRequisitionPDF = (solicitud: any, proveedor?: any) => {
  const doc = new jsPDF('p', 'mm', 'a4');
  const PAGE_WIDTH = doc.internal.pageSize.getWidth();
  let currentY = 10; // Punto de partida vertical

  const watchedMoneda = solicitud.moneda || solicitud.Moneda || 'CLP';

  const formatPDFCurrency = (amount: number) => {
    if (watchedMoneda === 'UF') {
      return `UF ${amount.toLocaleString('es-CL', { minimumFractionDigits: 2, maximumFractionDigits: 4 })} UF`;
    }
    const formatter = new Intl.NumberFormat(watchedMoneda === 'CLP' ? 'es-CL' : 'en-US', {
      style: 'currency',
      currency: watchedMoneda === 'CLP' ? 'CLP' : 'USD',
    });
    return `${formatter.format(amount)} ${watchedMoneda}`;
  };

  // Estilo por defecto para todo el documento
  doc.setFont('helvetica');
  doc.setFontSize(9);
  doc.setTextColor(...COLOR_TEXTO);

  // --- 1. ENCABEZADO: SECCIÓN SUPERIOR (Logo y Título de Registro) ---

  // Tabla 1: Logo y Título Principal
  autoTable(doc, {
    startY: currentY,
    body: [
      [
        { content: '', styles: { cellWidth: 50, minCellHeight: 20 } }, // Espacio para el logo
        {
          content: 'REGISTRO DE REQUISICIÓN DE COMPRAS',
          styles: {
            halign: 'center',
            valign: 'middle',
            fontSize: 12,
            fontStyle: 'bold',
            textColor: [0, 0, 0] // Negro puro para el título principal
          }
        }
      ]
    ],
    theme: 'plain', // Sin fondos por defecto
    margin: { left: 14, right: 14 },
    styles: { overflow: 'hidden' },
    didDrawCell: (data: any) => {
      // Dibujar el logo manualmente en la celda vacía
      if (data.row.index === 0 && data.column.index === 0 && LOGO_BASE64 && (LOGO_BASE64 as string) !== 'data:image/png;base64,') {
        doc.addImage(LOGO_BASE64, 'PNG', data.cell.x + 5, data.cell.y + 2, 40, 16);
      }
    }
  });

  // --- 2. ENCABEZADO: SECCIÓN DE CALIDAD (Código, Versión, Fecha) ---
  currentY = (doc as any).lastAutoTable.finalY;

  const qualityData = [
    ['Código:', 'R-CP-40', 'Página:', '1 de 1'],
    ['Versión:', '03', 'Fecha emisión:', '08-2023'],
    ['', '', 'Fecha vigencia:', '08-2024']
  ];

  autoTable(doc, {
    startY: currentY,
    head: [],
    body: qualityData,
    theme: 'grid',
    margin: { left: 14, right: 14 },
    styles: {
      fontSize: 8,
      cellPadding: 1,
      lineColor: COLOR_BORDE,
      halign: 'center'
    },
    columnStyles: {
      0: { cellWidth: 20, fontStyle: 'bold' },
      1: { cellWidth: 30 },
      2: { cellWidth: 30, fontStyle: 'bold' },
      3: { cellWidth: 30 }
    }
  });

  // --- 3. DATOS DE IDENTIFICACIÓN (No Requisición, Estatus, Fecha) ---
  currentY = (doc as any).lastAutoTable.finalY + 3; // Pequeño espacio

  autoTable(doc, {
    startY: currentY,
    body: [
      [
        { content: 'N° REQUISICION', styles: { fillColor: COLOR_FONDO_CABECERA, fontStyle: 'bold' } },
        solicitud.id || 'TEMP-001',
        { content: 'FECHA', styles: { fillColor: COLOR_FONDO_CABECERA, fontStyle: 'bold' } },
        format(new Date(), 'dd-MM-yyyy', { locale: es }),
        format(new Date(), 'HH:mm:ss')
      ],
      [
        { content: 'ESTATUS', styles: { fillColor: COLOR_FONDO_CABECERA, fontStyle: 'bold' } },
        solicitud.estatus || 'Vigente',
        '', '', '' // Celdas vacías
      ],
      [
        { content: 'FECHA ESTATUS', styles: { fillColor: COLOR_FONDO_CABECERA, fontStyle: 'bold' } },
        solicitud.fechaEstatus || format(new Date(), 'dd-MM-yyyy'),
        '', '', ''
      ]
    ],
    theme: 'grid',
    margin: { left: 14, right: 14 },
    styles: { fontSize: 8, cellPadding: 1.5, lineColor: COLOR_BORDE },
    columnStyles: {
      0: { cellWidth: 30 },
      1: { cellWidth: 40 },
      2: { cellWidth: 20 },
      3: { cellWidth: 30 },
      4: { cellWidth: 30 }
    }
  });

  // --- 4. DATOS DEL SOLICITANTE / PROVEEDOR (Bloque derecho de la imagen) ---
  currentY = (doc as any).lastAutoTable.finalY + 3;

  autoTable(doc, {
    startY: currentY,
    body: [
      [
        { content: 'Nombre Solicitante', styles: { fillColor: COLOR_FONDO_CABECERA, fontStyle: 'bold' } },
        solicitud.solicitanteName || '-'
      ],
      [
        { content: 'Cargo Solicitante', styles: { fillColor: COLOR_FONDO_CABECERA, fontStyle: 'bold' } },
        solicitud.cargo || '-'
      ],
      [
        { content: 'Centro de Costos', styles: { fillColor: COLOR_FONDO_CABECERA, fontStyle: 'bold' } },
        solicitud.centroCostos || '-'
      ],
      [
        { content: 'Centro de Negocio', styles: { fillColor: COLOR_FONDO_CABECERA, fontStyle: 'bold' } },
        solicitud.centroNegocios || '-'
      ],
      [
        { content: 'Proveedor', styles: { fillColor: COLOR_FONDO_CABECERA, fontStyle: 'bold' } },
        proveedor?.["RAZON SOCIAL"] || proveedor?.razonSocial || proveedor?.name || solicitud.proveedor || '-'
      ],
      [
        { content: 'RUT', styles: { fillColor: COLOR_FONDO_CABECERA, fontStyle: 'bold' } },
        proveedor?.["RUT"] || proveedor?.rut || '-'
      ],
      [
        { content: 'Dirección', styles: { fillColor: COLOR_FONDO_CABECERA, fontStyle: 'bold' } },
        proveedor?.["DIRECCION"] || proveedor?.direccion || '-'
      ],
      [
        { content: 'Ciudad', styles: { fillColor: COLOR_FONDO_CABECERA, fontStyle: 'bold' } },
        proveedor?.["CIUDAD"] || proveedor?.ciudad || '-'
      ],
      [
        { content: 'País', styles: { fillColor: COLOR_FONDO_CABECERA, fontStyle: 'bold' } },
        proveedor?.["PAÌS"] || proveedor?.pais || '-'
      ],
      [
        { content: 'Email / Correo', styles: { fillColor: COLOR_FONDO_CABECERA, fontStyle: 'bold' } },
        proveedor?.["EMAIL"] || proveedor?.email || '-'
      ]
    ],
    theme: 'grid',
    margin: { left: 14, right: 14 },
    styles: { fontSize: 8, cellPadding: 1.5, lineColor: COLOR_BORDE },
    columnStyles: {
      0: { cellWidth: 40 },
      1: { cellWidth: 'auto' } // Ocupa el resto del ancho
    }
  });

  // --- 5. TABLA PRINCIPAL DE ÍTEMS (Réplica exacta de columnas) ---
  currentY = (doc as any).lastAutoTable.finalY + 5;

  const tableData = solicitud.items.map((item: any, index: number) => [
    index + 1,
    item.codigoMaterial || '-',
    item.name, // Descripción
    item.cuentaPresupuesto || '-',
    formatPDFCurrency(item.estimatedCost), // Precio Unitario
    item.fechaEntrega || '-',
    formatPDFCurrency(item.quantity * item.estimatedCost) // Total Item
  ]);

  autoTable(doc, {
    startY: currentY,
    head: [['Item', 'Cód. Material', 'Descripción', 'Cuenta Presupuesto', 'Precio Unitario', 'Fecha de entrega', 'Subtotal']],
    body: tableData,
    theme: 'grid',
    margin: { left: 14, right: 14 },
    headStyles: {
      fillColor: COLOR_FONDO_CABECERA,
      textColor: COLOR_TEXTO,
      fontSize: 8,
      fontStyle: 'bold',
      halign: 'center',
      lineColor: COLOR_BORDE
    },
    styles: {
      fontSize: 7,
      cellPadding: 2,
      lineColor: COLOR_BORDE,
      valign: 'middle'
    },
    columnStyles: {
      0: { cellWidth: 10, halign: 'center' }, // Item
      1: { cellWidth: 25, halign: 'center' }, // Cód. Material
      2: { cellWidth: 'auto' },               // Descripción
      3: { cellWidth: 35, halign: 'center' }, // Cuenta Presupuesto
      4: { cellWidth: 'wrap', halign: 'right' }, // Precio Unitario
      5: { cellWidth: 25, halign: 'center' }, // Fecha entrega
      6: { cellWidth: 'wrap', halign: 'right' }, // Subtotal
    },
  });

  // --- 6. PIE DE PÁGINA: AUTORIZACIONES Y TOTALES ---
  currentY = (doc as any).lastAutoTable.finalY + 5;

  const totalNeto = solicitud.totalNeto || solicitud.Total_Neto || 0;
  const totalIva = solicitud.totalIva || solicitud.Total_IVA || 0;
  const totalGlobal = solicitud.totalGlobal || solicitud.Total_Global || solicitud.totalEstimatedCost || 0;

  // Fila de Autorizado y Totales (Desglosados)
  autoTable(doc, {
    startY: currentY,
    body: [
      [
        { content: 'AUTORIZADO POR:', styles: { fillColor: COLOR_FONDO_CABECERA, fontStyle: 'bold', cellWidth: 40 } },
        { content: solicitud.autorizadoPor || '', styles: { cellWidth: 60 } },
        { 
          content: 'MONTO NETO:\nIVA (19%):\nTOTAL REQUISICIÓN:',
          styles: { fillColor: COLOR_FONDO_CABECERA, halign: 'right', fontStyle: 'bold' } 
        },
        {
          content: `${formatPDFCurrency(totalNeto)}\n${formatPDFCurrency(totalIva)}\n${formatPDFCurrency(totalGlobal)}`,
          styles: { halign: 'right', fontStyle: 'bold', fontSize: 9 }
        }
      ]
    ],
    theme: 'grid',
    margin: { left: 14, right: 14 },
    styles: { fontSize: 8, cellPadding: 2, lineColor: COLOR_BORDE, valign: 'middle' },
    columnStyles: {
      0: { cellWidth: 40 },
      1: { cellWidth: 'auto' },
      2: { cellWidth: 40 },
      3: { cellWidth: 35 }
    },
  });

  // Fila de Observaciones
  currentY = (doc as any).lastAutoTable.finalY;
  autoTable(doc, {
    startY: currentY,
    body: [
      [
        { content: 'OBSERVACIONES:', styles: { fillColor: COLOR_FONDO_CABECERA, fontStyle: 'bold', cellWidth: 40 } },
        { content: solicitud.observaciones || '', styles: { minCellHeight: 15 } } // Celda alta para escribir
      ]
    ],
    theme: 'grid',
    margin: { left: 14, right: 14 },
    styles: { fontSize: 8, cellPadding: 2, lineColor: COLOR_BORDE, valign: 'top' }
  });

  // --- Guardar ---
  const fileName = `RE${solicitud.id || 'NUEVA'}.pdf`;
  doc.save(fileName);
};